const pruningPolicyAdmissionWitnessAuthorityTransitionAdmissionWitnessFixture = (
  transitionFixture: ReturnType<
    typeof pruningPolicyAdmissionWitnessAuthorityTransitionAdmissionFixture
  >,
  options: {
    readonly finalSubjectHash?: string;
    readonly finalAcceptedWitnessIds?: readonly string[];
    readonly finalAuthorityTopologyHash?: string;
    readonly witnessAuthorityTopology?: ReturnType<
      typeof pruningPolicyAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTopology
    >;
    readonly witnessAuthorityTransitionAdmissionReplay?: ReturnType<
      typeof pruningPolicyAdmissionWitnessAuthorityTransitionAdmissionWitnessAuthorityTransitionAdmissionFixture
    >["replay"];
    readonly requireWitnessAuthorityTransitionAdmission?: boolean;
  } = {},
) => {
  const transitionAdmissionWitnessStoreId =
    "pruning-policy-admission-witness-authority-transition-admission-witnesses";
  const authorityBoundary =
    "operational_state_pruning_policy_admission_witness_authority_transition_admission_witness";
  const buildWitnessRecord = (
    admissionRecord: (typeof transitionFixture.records)[number],
    witnessSequence: number,
    previousWitnessRecordHash?: string,
  ) =>
    buildOperationalStatePruningPolicyAdmissionWitnessAuthorityTransitionAdmissionWitnessRecord(
      {
        tenantId: admissionRecord.tenantId,
        transitionAdmissionWitnessStoreId,
        transitionAdmissionStoreId:
          transitionFixture.transitionAdmissionStoreId,
        topologyId: transitionFixture.topologyId,
        authorityScope: admissionRecord.authorityScope,
        witnessSequence,
        admissionSequence: admissionRecord.admissionSequence,
        authoritySequence: admissionRecord.authoritySequence,
        authorityRecordHash: admissionRecord.authorityRecordHash,
        admissionRecordHash: admissionRecord.admissionRecordHash,
        nextAuthorityTopologyHash: admissionRecord.nextAuthorityTopologyHash,
        admissionCertificate:
          buildOperationalStateQuorumCertificateProofCertificate({
            tenantId: admissionRecord.tenantId,
            authorityScope: admissionRecord.authorityScope,
            authorityBoundary,
            subjectKind:
              OPERATIONAL_STATE_PRUNING_POLICY_ADMISSION_WITNESS_AUTHORITY_TRANSITION_ADMISSION_RECORD_SUBJECT_KIND,
            subjectId: `${transitionFixture.transitionAdmissionStoreId}:${transitionFixture.topologyId}`,
            subjectSequence: admissionRecord.admissionSequence,
            subjectHash:
              witnessSequence === transitionFixture.records.length
                ? options.finalSubjectHash ?? admissionRecord.admissionRecordHash
                : admissionRecord.admissionRecordHash,
            status: "certified",
            certified: true,
            acceptedWitnessIds:
              witnessSequence === transitionFixture.records.length
                ? options.finalAcceptedWitnessIds ?? [
                    "pruning-policy-transition-admission-witness:a",
                    "pruning-policy-transition-admission-witness:b",
                  ]
                : [
                    "pruning-policy-transition-admission-witness:a",
                    "pruning-policy-transition-admission-witness:b",
                  ],
            requiredWitnesses: 2,
            minimumWitnesses: 2,
            ...(witnessSequence === transitionFixture.records.length
              ? options.finalAuthorityTopologyHash !== undefined
                ? { authorityTopologyHash: options.finalAuthorityTopologyHash }
                : options.witnessAuthorityTopology !== undefined
                  ? {
                      authorityTopologyHash:
                        options.witnessAuthorityTopology.topologyHash,
                    }
                  : {}
              : options.witnessAuthorityTopology !== undefined
                ? {
                    authorityTopologyHash:
                      options.witnessAuthorityTopology.topologyHash,
                  }
                : {}),
            certifiedAt: timestamp(
              `2026-06-03T14:09:3${witnessSequence}.000Z`,
            ),
            certifiedBy:
              "authority:pruning-policy-witness-transition-admission-witness",
          }),
        ...(previousWitnessRecordHash !== undefined
          ? { previousWitnessRecordHash }
          : {}),
        witnessedAt: timestamp(`2026-06-03T14:09:3${witnessSequence}.100Z`),
        witnessedBy:
          "authority:pruning-policy-witness-transition-admission-witness",
        witnessReason:
          "witness-pruning-policy-witness-authority-transition-admission",
      },
    );

  const records: ReturnType<typeof buildWitnessRecord>[] = [];
  transitionFixture.records.forEach((admissionRecord, index) => {
    records.push(
      buildWitnessRecord(
        admissionRecord,
        index + 1,
        records[index - 1]?.witnessRecordHash,
      ),
    );
  });
  const replay =
    replayOperationalStatePruningPolicyAdmissionWitnessAuthorityTransitionAdmissionWitnessRecords(
      {
        tenantId: transitionFixture.records[0].tenantId,
        transitionAdmissionWitnessStoreId,
        transitionAdmissionStoreId:
          transitionFixture.transitionAdmissionStoreId,
        topologyId: transitionFixture.topologyId,
        authorityScope: transitionFixture.records[0].authorityScope,
        records,
        admissionReplay: transitionFixture.replay,
        requiredAdmissionRecord:
          transitionFixture.replay.latestAdmittedRecord,
        requiredAuthorityBoundary: authorityBoundary,
        ...(options.witnessAuthorityTopology !== undefined
          ? {
              witnessAuthorityTopology: options.witnessAuthorityTopology,
              requireWitnessAuthorityTopology: true,
            }
          : {}),
        ...(options.witnessAuthorityTransitionAdmissionReplay !== undefined
          ? {
              witnessAuthorityTransitionAdmissionReplay:
                options.witnessAuthorityTransitionAdmissionReplay,
            }
          : {}),
        ...(options.requireWitnessAuthorityTransitionAdmission !== undefined ||
        options.witnessAuthorityTransitionAdmissionReplay !== undefined
          ? {
              requireWitnessAuthorityTransitionAdmission:
                options.requireWitnessAuthorityTransitionAdmission ?? true,
            }
          : {}),
      },
    );

  return {
    transitionAdmissionWitnessStoreId,
    authorityBoundary,
    records,
    replay,
  };
};

