const signedHistoryRootObservation = (
  observation: ReturnType<typeof buildOperationalStateHistoryRootObservation>,
  options: {
    readonly keyStatus?: "active" | "suspended" | "revoked" | "rotated" | "unknown";
    readonly observerId?: string;
    readonly verifierId?: string;
    readonly adapterClaims?: Parameters<
      typeof buildOperationalStateSignatureVerifierAdapterProof
    >[0]["adapterClaims"];
    readonly signatureHash?: string;
  } = {},
) => {
  const observerId = options.observerId ?? observation.observerId;
  const keyBinding = buildOperationalStateSignatureKeyBinding({
    tenantId: observation.tenantId,
    authorityScope: observation.root.authorityScope,
    principalId: observerId,
    keyId: `${observerId}:key:v1`,
    algorithm: "ed25519",
    keyStatus: options.keyStatus ?? "active",
    authoritySequence: 1,
    authorityTopologyHash: "topology:history-root-observers:v1",
    publicKeyFingerprint: `fp:${observerId}:key:v1`,
    keyMaterialHash: `key-material:${observerId}:key:v1`,
  });
  const payloadHash =
    computeOperationalStateHistoryRootObserverSignaturePayloadHash(
      observation,
    );
  const verifierProof = buildOperationalStateSignatureVerifierAdapterProof({
    verificationId: `verification:${observerId}:${observation.observationHash}`,
    tenantId: observation.tenantId,
    authorityScope: observation.root.authorityScope,
    verifierId: options.verifierId ?? "kms-ed25519",
    verifierVersion: "2026-06-27",
    verifiedAt: observation.observedAt,
    principalId: observerId,
    keyId: keyBinding.keyId,
    algorithm: keyBinding.algorithm,
    payloadHash,
    signatureHash:
      options.signatureHash ??
      `signature:${observerId}:${observation.observationHash}`,
    keyBindingHash: keyBinding.keyBindingHash,
    publicKeyFingerprint: keyBinding.publicKeyFingerprint,
    keyMaterialHash: keyBinding.keyMaterialHash,
    result: "valid",
    adapterClaims: options.adapterClaims ?? ["signature_validity"],
  });
  return buildOperationalStateHistoryRootObserverSignatureProof({
    observation,
    observerKeyBinding: keyBinding,
    verifierProof,
  });
};

