  it("recovers authority topology from compacted checkpoints plus retained transitions", () => {
    const setQuorum = buildOperationalStateAuthorityTransitionRecord({
      tenantId: t,
      topologyId: "ops-authority-topology",
      authorityScope: "agent-state:ops",
      authoritySequence: 1,
      transitionKind: "set_quorum",
      recordedAt: timestamp("2026-06-27T16:00:00.000Z"),
      recordedBy: "authority-admin",
      effectiveFromSubjectSequence: 1,
      requiredWitnesses: 2,
      minimumWitnesses: 2,
    });
    const admitObserverA = buildOperationalStateAuthorityTransitionRecord({
      tenantId: t,
      topologyId: "ops-authority-topology",
      authorityScope: "agent-state:ops",
      authoritySequence: 2,
      previousAuthorityRecordHash: setQuorum.authorityRecordHash,
      transitionKind: "admit_principal",
      recordedAt: timestamp("2026-06-27T16:01:00.000Z"),
      recordedBy: "authority-admin",
      effectiveFromSubjectSequence: 1,
      principalId: "observer:a",
      signatureKeyId: "observer:a:key:v1",
    });
    const compactedTopology = operationalStateAuthorityTopologyFromTransition(
      admitObserverA,
      operationalStateAuthorityTopologyFromTransition(setQuorum),
    );
    const checkpoint =
      buildOperationalStateAuthorityTopologyCompactionCheckpoint({
        checkpointId: "authority-topology-checkpoint:2",
        tenantId: t,
        topologyId: "ops-authority-topology",
        authorityScope: "agent-state:ops",
        compactedThroughAuthoritySequence: 2,
        compactedTopology,
        retainedFromAuthoritySequence: 3,
        checkpointedAt: timestamp("2026-06-27T16:02:00.000Z"),
        checkpointedBy: "authority-compactor",
      });
    const admitObserverB = buildOperationalStateAuthorityTransitionRecord({
      tenantId: t,
      topologyId: "ops-authority-topology",
      authorityScope: "agent-state:ops",
      authoritySequence: 3,
      previousAuthorityRecordHash: admitObserverA.authorityRecordHash,
      transitionKind: "admit_principal",
      recordedAt: timestamp("2026-06-27T16:03:00.000Z"),
      recordedBy: "authority-admin",
      effectiveFromSubjectSequence: 4,
      principalId: "observer:b",
      signatureKeyId: "observer:b:key:v1",
    });
    const rotateObserverA = buildOperationalStateAuthorityTransitionRecord({
      tenantId: t,
      topologyId: "ops-authority-topology",
      authorityScope: "agent-state:ops",
      authoritySequence: 4,
      previousAuthorityRecordHash: admitObserverB.authorityRecordHash,
      transitionKind: "rotate_signature_key",
      recordedAt: timestamp("2026-06-27T16:04:00.000Z"),
      recordedBy: "authority-admin",
      effectiveFromSubjectSequence: 5,
      principalId: "observer:a",
      signatureKeyId: "observer:a:key:v2",
    });
    const topologyAfterObserverB = operationalStateAuthorityTopologyFromTransition(
      admitObserverB,
      compactedTopology,
    );
    const requiredTopology = operationalStateAuthorityTopologyFromTransition(
      rotateObserverA,
      topologyAfterObserverB,
    );

    const evaluation = evaluateOperationalStateAuthorityTopologyCompaction({
      checkpoint,
      retainedTransitions: [admitObserverB, rotateObserverA],
      requiredTopology,
    });

    expect(evaluation).toMatchObject({
      valid: true,
      appliedTransitionCount: 2,
      currentTopology: {
        authoritySequence: 4,
        topologyHash: requiredTopology.topologyHash,
      },
      issues: [],
    });
    expect(evaluation.currentTopology?.principals).toEqual([
      {
        principalId: "observer:a",
        status: "active",
        signatureKeyId: "observer:a:key:v2",
        updatedAtAuthoritySequence: 4,
      },
      {
        principalId: "observer:b",
        status: "active",
        signatureKeyId: "observer:b:key:v1",
        updatedAtAuthoritySequence: 3,
      },
    ]);
  });

